@concat('.append AlertLogs <|    
    let lastRunParam = toscalar(MonitoringLastRunTime | summarize max(LastRunTime));
    let startTimeFilter = iff(isnull(lastRunParam), ago(100d), lastRunParam);
    let ak = AllowedItemKind;
    let wl = WorkspaceLogs
    | where ingestion_time() > startTimeFilter
    | where ingestion_time() < todatetime("', variables('now'),'")
    | extend IngestionTime = ingestion_time()
    | where type == "Microsoft.Fabric.ItemCreateSucceeded"
    | project WorkspaceName = data_workspaceName, data_workspaceId, wstime = ["time"], data_itemName, data_itemId, data_itemKind, type, IngestionTime, UserId = data_executingPrincipalId;
    let aop =
    DataverseWorkspace
    | extend IngestionTime = ingestion_time()
    | summarize arg_max(IngestionTime, *) by WorkspaceId
    | where OAPActivity == "DisableWorkspaceOutboundAccessProtection"
    | where IsMonitored == true
    | project WorkspaceId, Activity= OAPActivity;
    wl
    | join kind = inner 
        aop
        on  $left.data_workspaceId == $right.WorkspaceId
    | join kind = leftanti 
        ak
        on $left.data_itemKind == $right.ItemKind
    | extend AlertStatus = "Initial"
    | project WorkspaceName, WorkspaceId, wstime, data_itemKind, data_itemName, data_itemId, AlertStatus, UserId
    // 3. Filter out records that already exist in the destination table
    | join kind=leftanti (
        AlertLogs 
    ) on WorkspaceId, data_itemId')

@concat('.set-or-append AlertLogs <| 
let targetWorkspaceId = toguid("', item().WorkspaceId,'");
let targetItemIdsString = "', item().ItemIds,'";
let targetItemIds = split(replace_string(targetItemIdsString, " ", ""), ",");
AlertLogs
| extend IngestionTime = ingestion_time()
| summarize arg_max(IngestionTime, *) by WorkspaceId, data_itemId
| where WorkspaceId == targetWorkspaceId and data_itemId in (targetItemIds)
| project WorkspaceName, WorkspaceId, wstime, data_itemKind, data_itemName, data_itemId, AlertStatus = "EmailSent", UserId
')

@concat('.append AOPAlertLogs <|
let lastRunParam = toscalar(MonitoringLastRunTime | summarize max(LastRunTime));
let startTimeFilter = case(isnull(lastRunParam), ago(100d), lastRunParam > ago(1h), ago(1h), lastRunParam);
let daop =
DataverseWorkspace
| summarize arg_max(ingestion_time(), OAPActivity, IsMonitored) by WorkspaceId
| where IsMonitored = true
| project daopWorkspaceId = WorkspaceId, daopActivity = OAPActivity;
let aop = 
WorkspaceOutboundAccessProtection
| where ingestion_time() > startTimeFilter
| where ingestion_time() < todatetime("', variables('now'),'")
| project Activity, WorkspaceId, CreationTime,Id, UserId, UserKey;
let laop = 
WorkspaceOutboundAccessProtection
| where ingestion_time() > startTimeFilter
| where ingestion_time() < todatetime("', variables('now'),'")
| summarize arg_max(CreationTime, Activity) by WorkspaceId
| project WorkspaceId, LastActivity = Activity;
let al = AOPAlertLogs
| project Id;
aop
| join kind=inner (
    daop 
) on $left.WorkspaceId == $right.daopWorkspaceId
| join kind=inner (
    laop
) on WorkspaceId
| join kind=leftanti (
    al
) on Id
| where Activity !=daopActivity
| project WorkspaceId, ToChangeAOP = iif(LastActivity==daopActivity,false,true), AOP = LastActivity, AOPMustBe = daopActivity, CreationTime, UserId, AlertStatus = "Initial", Id, UserKey')

@concat('.append AOPAlertLogs <|
let targetWorkspaceId = toguid("', item().WorkspaceId,'");
let TargetIdsString = "', item().Ids,'";
let targetIds = split(replace_string(TargetIdsString," ", ""),  ",");
AOPAlertLogs
| where ingestion_time() > todatetime("', variables('now'), '")
| summarize arg_max(CreationTime, *) by WorkspaceId, Id
| where AlertStatus == "Initial"
| where WorkspaceId == targetWorkspaceId and Id in (targetIds)
| project WorkspaceId, ToChangeAOP, AOP, AOPMustBe, CreationTime, UserId, AlertStatus = "EmailSent", Id, UserKey
')
